function renderBannerText(text, fontSize) {
	const BW = 104, TOTAL = 4838;
	const F = fontSize === 18 ? BANNER_FONT_18 : fontSize === 24 ? BANNER_FONT_24 : BANNER_FONT_14;
	const buf = new Array(TOTAL).fill(0);
	let x = 0;
	for (let i = 0; i < text.length && x < BW; i++) {
		const g = F[text.charCodeAt(i)];
		if (!g) continue;
		const px = g[1];
		for (let j = 0; j < px.length; j += 2) {
			const col = px[j+1] + x;
			if (col < BW) buf[px[j] * BW + col] = 255;
		}
		x += g[0];
	}
	return buf;
}


export class AsusKeyboard{
	constructor() {
		this.Config = {
			DeviceProductID: 0x0000,
			DeviceName: "Asus Device",
			Leds: [],
			LedNames: [],
			LedPositions: [],
			lastRGBData: null,
		};
	}

	getDeviceName() { return this.Config.DeviceName; }
	setDeviceName(deviceName) { this.Config.DeviceName = deviceName; }

	getLedsPerPacket() { return this.Config.ledsPerPacket; }
	setLedsPerPacket(ledsperpacket) { this.Config.ledsPerPacket = ledsperpacket; }

	getLeds() { return this.Config.Leds; }
	setLeds(leds) { this.Config.Leds = leds; }

	getLedNames() { return this.Config.LedNames; }
	setLedNames(ledNames) { this.Config.LedNames = ledNames; }

	getLedPositions() { return this.Config.LedPositions; }
	setLedPositions(ledPositions) { this.Config.LedPositions = ledPositions; }

	getDeviceImage() { return this.Config.image; }
	setDeviceImage(image) { this.Config.image = image; }

	initializeAsus(deviceName) {

		const DeviceProperties = keyboardLibrary.GetMappingFromName(deviceName);

		if(DeviceProperties){
			this.setDeviceName(deviceName);
			this.setLeds(DeviceProperties.vLeds);
			this.setLedNames(DeviceProperties.vLedNames);
			this.setLedPositions(DeviceProperties.vLedPositions);
			this.setDeviceImage(DeviceProperties.image);

			console.log(`Device model found: ` + this.getDeviceName());
			device.setName("ASUS " + this.getDeviceName());
			device.setSize(DeviceProperties.size);
			device.setControllableLeds(this.getLedNames(), this.getLedPositions());
			device.setImageFromUrl(this.getDeviceImage());

			device.addProperty({"property":"idleTimeout", "group":"", "label":"Device Sleep Timeout (Minutes)", description: "Enables the device to enter sleep mode", "type":"combobox", "values":["Off", "1", "2", "3", "5", "10",], "default":"3"});
			this.setIdleTimeout();

			device.addProperty({"property":"keyDebounce", "group":"", "label":"Key Debounce (ms)", "description":"Filters out accidental double keystrokes.", "type":"combobox", "values":["15", "20", "25", "30", "35", "40", "45", "50"], "default":"15"});
			this.setDebounce();

			device.addProperty({"property":"oledMode", "group":"", "label":"OLED Mode", "description":"Animation plays alongside RGB. Banner stops RGB lighting (keyboard uses stored preset).", "type":"combobox", "values":["Animation", "Banner"], "default":"Animation"});
			device.addProperty({"property":"oledAnimation", "group":"", "label":"OLED Animation", "description":"Sets the animation displayed on the OLED screen.", "type":"combobox", "values":["ROG Logo", "Republic of Gamers", "Cityscape", "ROG Republic of Gamers", "Floating Hearts", "ROG Triangle"], "default":"ROG Logo", "if":"oledMode == Animation"});
			device.addProperty({"property":"oledBanner", "group":"", "label":"OLED Banner Style", "description":"Sets the banner. RGB lighting is paused while banner is active.", "type":"combobox", "values":["Black", "Diagonal Stripes", "ROG Diagonal", "ROG Repeat", "Checkered", "Chevron"], "default":"Diagonal Stripes", "if":"oledMode == Banner"});
			device.addProperty({"property":"oledBannerText", "group":"", "label":"OLED Banner Text", "description":"Custom text on the banner.", "type":"textfield", "default":"", "if":"oledMode == Banner"});
			device.addProperty({"property":"oledBannerFontSize", "group":"", "label":"OLED Banner Font Size", "description":"Font size for the banner text.", "type":"combobox", "values":["14px","18px","24px"], "default":"14px", "if":"oledMode == Banner"});
			this.setOledContent();

			device.addFeature("battery");
			this.modernFetchBatteryLevel();
		}else{
			device.notify("Unknown device", `Reach out to support@signalrgb.com, or visit our Discord to get it added.`, 0);
			console.log("Model not found in library!");
		}
	}

	sendColors(overrideColor) {

		if(this.getDeviceName() === "Asus Device"){
			return;
		}

		const deviceLeds = this.getLeds();
		const deviceLedPositions = this.getLedPositions();
		const TotalLEDs = deviceLeds.length;
		const RGBData = [];

		let TotalLedCount = TotalLEDs;

		for (let iIdx = 0; iIdx < TotalLEDs; iIdx++) {
			const iPxX = deviceLedPositions[iIdx][0];
			const iPxY = deviceLedPositions[iIdx][1];
			let color;

			if (overrideColor) {
				color = hexToRgb(overrideColor);
			} else if (LightingMode === "Forced") {
				color = hexToRgb(forcedColor);
			} else {
				color = device.color(iPxX, iPxY);
			}

			RGBData[iIdx * 4 + 0] = deviceLeds[iIdx];
			RGBData[iIdx * 4 + 1] = color[0];
			RGBData[iIdx * 4 + 2] = color[1];
			RGBData[iIdx * 4 + 3] = color[2];
		}

		const key = RGBData.join(",");
		if (!overrideColor && key === this.Config.lastRGBData) return;
		this.Config.lastRGBData = key;

		while (TotalLedCount > 0) {
			const ledsPerPacket = 14;

			const ledsToSend = TotalLedCount >= ledsPerPacket ? ledsPerPacket : TotalLedCount;

			device.write([0x02, 0xC0, 0x81, ledsToSend, 0x00].concat(RGBData.splice(0, ledsToSend * 4)), 65);
			TotalLedCount -= ledsToSend;
		}
	}

	getDeviceBatteryStatus() {
		if(this.getDeviceName() === "Asus Device"){
			return;
		}

		if (Date.now() - savedPollTimer < PollModeInternal) {
			return;
		}

		    savedPollTimer = Date.now();

		this.modernFetchBatteryLevel();
	}

	modernFetchBatteryLevel() {
		device.write([0x02, 0x12, 0x03], 64);
		device.pause(10);

		const returnpacket = this.sendPacketWithResponse([0x02, 0x12, 0x01]);

		if (!returnpacket || returnpacket.length < 10) {
			device.log("⚠️ Battery read failed or returned empty packet.");

			return;
		}

		const batteryLevel = returnpacket[6];
		const batteryState = returnpacket[9] + 1;

		device.log(`🔋 Battery: ${batteryLevel}% | State: ${keyboardLibrary.chargingStates[batteryState]}`);
		//TODO: Make this a dict
		battery.setBatteryLevel(batteryLevel);
		battery.setBatteryState(batteryState);
	}

	setIdleTimeout() {
		const timeMap = {
			1: 0x00,
			2: 0x01,
			3: 0x02,
			5: 0x03,
			10: 0x04,
			0: 0xFF // 0 = Off / disabled
		};

		// fallback if invalid value
		const encoded = timeMap.hasOwnProperty(idleTimeout) ? timeMap[idleTimeout] : 0x02;

		device.write([0x02, 0x51, 0x38, 0x00, 0x00, encoded], 64);
		device.pause(5);

		//save
		device.write([0x02, 0x50, 0x55, 0x00, 0x00], 64);
		device.pause(5);

		device.log(`🛌 Set idle timeout to ${idleTimeout === 0 ? "Off" : idleTimeout + " min"}`);
	}

	setOledContent() {
		if (oledMode === "Banner") {
			this.setBanner();
		} else {
			this.setOledAnimation();
		}
	}

	setOledAnimation() {
		const animationMap = {
			"ROG Logo": 0x00,
			"Republic of Gamers": 0x01,
			"Cityscape": 0x02,
			"ROG Republic of Gamers": 0x03,
			"Floating Hearts": 0x04,
			"ROG Triangle": 0x05,
		};
		const index = animationMap[oledAnimation] ?? 0x00;
		device.write([0x02, 0x61, 0x00, 0x00, 0x00, index], 64);
		device.pause(20);
		device.write([0x02, 0x50, 0x55, 0x00, 0x00], 64);
		device.pause(5);
		device.log(`OLED Animation: ${oledAnimation}`);
	}

	setBanner() {
		const bannerIndexMap = {
			"Black":            { index: 0xFF, totalBytes: 6667, packets: 113, h: 0x40 },
			"Diagonal Stripes": { index: 0x00, totalBytes: 4838, packets: 82,  h: 0x2E },
			"ROG Diagonal":     { index: 0x01, totalBytes: 4838, packets: 82,  h: 0x2E },
			"ROG Repeat":       { index: 0x02, totalBytes: 4838, packets: 82,  h: 0x2E },
			"Checkered":        { index: 0x03, totalBytes: 4838, packets: 82,  h: 0x2E },
			"Chevron":          { index: 0x04, totalBytes: 4838, packets: 82,  h: 0x2E },
		};
		const cfg = bannerIndexMap[oledBanner] !== undefined ? bannerIndexMap[oledBanner] : bannerIndexMap["Diagonal Stripes"];

		// Render text using embedded bitmap font
		const fontSize = oledBannerFontSize === "18px" ? 18 : oledBannerFontSize === "24px" ? 24 : 14;
		const buf = renderBannerText(oledBannerText || "", fontSize);

		// Header
		const header = [0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00];
		header[0]=0x02; header[1]=0x62; header[2]=0x00; header[5]=cfg.index;
		header[6]=0x01; header[7]=0xD0; header[8]=0x00; header[9]=cfg.h;
		header[11]=cfg.packets & 0xFF; header[12]=(cfg.packets >> 8) & 0xFF;
		device.write(header, 64);
		device.pause(10);

		// Data packets – 15ms delay required for OMNI dongle wireless relay
		const CHUNK = 59;
		for (let i = 0; i < cfg.packets; i++) {
			const counter = cfg.packets - 1 - i;
			const pkt = [0x02,0x62,0x01,counter & 0xFF,(counter >> 8) & 0xFF,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00];
			const offset = i * CHUNK;
			for (let j = 0; j < CHUNK; j++) pkt[5+j] = (offset+j < buf.length) ? buf[offset+j] : 0;
			device.write(pkt, 64);
			device.pause(15);
		}

		device.write([0x02,0x62,0x02,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00], 64);
		device.pause(20);
		device.write([0x02,0x50,0x55,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00], 64);
		device.pause(5);
		device.log(`OLED Banner: ${oledBanner} (index=0x${cfg.index.toString(16).padStart(2,"0")})`);
	}


	setDebounce() {
		const ms = parseInt(keyDebounce) || 0;
		device.write([0x02, 0x6C, 0x00, 0x00, 0x00, ms], 64);
		device.pause(20);
		device.write([0x02, 0x50, 0x55, 0x00, 0x00], 64);
		device.pause(5);
		device.log(`⌨️ Set debounce to ${ms}ms`);
	}

	sendPacketWithResponse(packet) {
		device.clearReadBuffer();

		device.write(packet, 64);
		device.pause(10);

		const returnPacket = device.read(packet, 64);

		return returnPacket;
	}
}

